function.arguments:
{"script":"cd student_data 2>/dev/null || { echo 0; exit 0; }
shopt -s nullglob
files=( *)
if [ ${#files[@]} -eq 0 ]; then echo 0; exit 0; fi
awk 'BEGIN{n=0;s1=s2=s3=0} NF>=4{n++; s1+=$2; s2+=$3; s3+=$4} END{ if(n>0) printf "%d\n", int(s1/n)+int(s2/n)+int(s3/n); else print 0 }' "${files[@]}""}
